#' Export External Evaluation PDF Report
#'
#' Generates a multi-page PDF report summarizing external pharmacokinetic
#' evaluation results, including metadata, performance summaries,
#' diagnostic plots, and optional individual fit visualizations.
#'
#' This function supports objects generated from the external evaluation
#' workflow, including complete evaluation objects, metric summaries,
#' or raw evaluation datasets.
#'
#' @param x An object containing evaluation results. Supported inputs are:
#' \itemize{
#'   \item \code{EvalPPK}: complete external evaluation object generated by
#'   \code{exeval_ppk()}.
#'   \item \code{EvalMetricsPPK}: metrics object generated from
#'   \code{metrics_occ()}.
#'   \item \code{data.frame}: raw observation-level evaluation dataset
#'   containing prediction error metrics.
#' }
#'
#' @param file Character string specifying the output PDF file path.
#' Default is \code{"external_evaluation_report.pdf"}.
#'
#' @param include_logo Logical. Whether to include the package logo on the
#' title page. Default is \code{TRUE}.
#'
#' @param logo_path Optional character string specifying the path to a custom
#' logo image (.png). If \code{NULL}, the package default logo is used.
#'
#' @param include_plots Logical. Whether to include the fit distribution plot.
#' Default is \code{TRUE}.
#'
#' @param include_metrics_plot Logical. Whether to include performance metric
#' plots generated from \code{metrics_plot()}. Default is \code{TRUE}.
#'
#' @param metrics_plot_types Character vector specifying which performance
#' plots to include. Available options include:
#' \itemize{
#'   \item \code{"bias_barplot"}
#'   \item \code{"bias_pointrange"}
#'   \item \code{"MAIPE_barplot"}
#'   \item \code{"bias_boxplot"}
#'   \item \code{"bias_violin"}
#'   \item \code{"bias_dotplot"}
#'   \item \code{"bias_density"}
#'   \item \code{"IF20_plot"}
#'   \item \code{"IF30_plot"}
#'   \item \code{"IF_plot"}
#'   \item \code{"error_plot"}
#' }
#'
#' @param include_individual_plots Logical. Whether to include individual fit
#' plots for poorly fitted subjects. Default is \code{TRUE}.
#'
#' @param n_individual_plots Integer specifying the maximum number of
#' individual fit plots to include. Default is \code{3}.
#'
#' @param include_screen_fit Logical. Whether to include the screen fit
#' summary section highlighting observations meeting selected fit criteria.
#' Default is \code{TRUE}.
#'
#' @param fit_classes Character vector specifying fit quality categories to
#' include in the screen fit summary. Default is
#' \code{c("Poor", "Very Poor")}.
#'
#' @param occ Optional numeric value specifying a single occasion to restrict
#' summary statistics and plots.
#'
#' @details
#' This function creates a publication-style PDF report for external PK model
#' evaluation workflows.
#'
#' Depending on the provided input object, the report may include:
#' \itemize{
#'   \item Title page with evaluation metadata
#'   \item Summary dashboard with global performance metrics
#'   \item Fit distribution summary
#'   \item Screen fit summary
#'   \item Poorly fitted subject summary
#'   \item Fit distribution plots
#'   \item Performance metric plots
#'   \item Individual diagnostic plots
#' }
#'
#' If a package logo is unavailable or the provided logo path is invalid,
#' the report is generated without a logo.
#'
#' Individual fit plots are only generated when a full \code{EvalPPK}
#' object is supplied.
#'
#' @return Invisibly returns the path to the exported PDF file.
#'
#' @seealso
#' \code{\link{exeval_ppk}},
#' \code{\link{metrics_occ}},
#' \code{\link{metrics_plot}},
#' \code{\link{plot_individual_fit}},
#' \code{\link{screen_fit}},
#' \code{\link{summary.EvalPPK}}
#'
#' @examples
#' \dontrun{
#'
#' # Export report from complete evaluation object
#' export_evaluation_pdf(eval_obj)
#'
#' # Export report without package logo
#' export_evaluation_pdf(
#'   eval_obj,
#'   file = "tacrolimus_external_eval.pdf",
#'   include_logo = FALSE
#' )
#'
#' # Export only selected performance plots
#' export_evaluation_pdf(
#'   eval_obj,
#'   metrics_plot_types = c("bias_barplot", "IF30_plot")
#' )
#'
#' # Export report for a specific occasion
#' export_evaluation_pdf(
#'   eval_obj,
#'   occ = 3
#' )
#'
#' }
#'
#' @export
#'
#'
export_evaluation_pdf <- function(
    x,
    file = "external_evaluation_report.pdf",
    include_logo = TRUE,
    logo_path = NULL,
    include_plots = TRUE,
    include_metrics_plot = TRUE,
    metrics_plot_types = c("bias_barplot","bias_pointrange","MAIPE_barplot",
                           "bias_boxplot","bias_violin", "bias_dotplot",
                           "bias_density", "IF20_plot","IF30_plot","IF_plot",
                           "error_plot"
    ),
    include_individual_plots = TRUE,
    n_individual_plots = 3,
    include_screen_fit = TRUE,
    fit_classes = c("Poor", "Very Poor"),
    occ = NULL
) {

  if (!requireNamespace("gridExtra", quietly = TRUE)) {
    stop("Package 'gridExtra' is required.")
  }

  if (include_logo && !requireNamespace("png", quietly = TRUE)) {
    stop("Package 'png' is required for logo rendering.")
  }
  # --------------------------------
  # Helpers
  # --------------------------------
  format_numeric_df <- function(df, digits = 2) {
    if (is.null(df)) return(NULL)

    df %>%
      dplyr::mutate(
        dplyr::across(
          where(is.numeric),
          ~ round(.x, digits)
        )
      )
  }

  pretty_eval_name <- function(x) {
    if (is.null(x) || length(x) == 0) return("")

    x <- gsub("_", " ", x)
    tools::toTitleCase(x)
  }

  styled_table <- function(df) {
    if (is.null(df) || nrow(df) == 0) return(NULL)

    df <- format_numeric_df(df)

    gridExtra::tableGrob(
      df,
      rows = NULL,
      theme = gridExtra::ttheme_minimal(
        core = list(
          fg_params = list(cex = 0.85)
        ),
        colhead = list(
          fg_params = list(
            fontface = "bold",
            cex = 0.9
          ),
          bg_params = list(
            fill = "grey85"
          )
        )
      )
    )
  }

  add_title_page <- function(metadata, logo = NULL) {
    grid::grid.newpage()

    if (!is.null(logo) && file.exists(logo)) {
      img <- png::readPNG(logo)
      raster <- grid::rasterGrob(img)

      grid::grid.draw(
        grid::editGrob(
          raster,
          vp = grid::viewport(
            x = 0.5,
            y = 0.85,
            width = 0.3,
            height = 0.15
          )
        )
      )
    }

    grid::grid.text(
      "External PK Evaluation Report",
      y = 0.68,
      gp = grid::gpar(
        fontsize = 22,
        fontface = "bold"
      )
    )

    grid::grid.text(
      format(Sys.time(), "%Y-%m-%d %H:%M"),
      y = 0.63,
      gp = grid::gpar(fontsize = 10)
    )

    if (!is.null(metadata)) {

      y0 <- 0.52

      for (i in seq_len(nrow(metadata))) {

        ypos <- y0 - ((i - 1) * 0.045)

        label <- paste0(metadata[i, 1], ":")
        value <- pretty_eval_name(as.character(metadata[i, 2]))

        # Bold label
        grid::grid.text(
          label,
          x = 0.12,
          y = ypos,
          just = "left",
          gp = grid::gpar(
            fontsize = 11,
            fontface = "bold"
          )
        )

        # Regular value
        grid::grid.text(
          value,
          x = 0.45,
          y = ypos,
          just = "left",
          gp = grid::gpar(
            fontsize = 11
          )
        )
      }
    }


  }

  add_table_page <- function(title, df) {

    if (is.null(df) || nrow(df) == 0) {
      return(invisible(NULL))
    }

    grid::grid.newpage()

    grid::grid.text(
      title,
      y = 0.95,
      gp = grid::gpar(
        fontsize = 16,
        fontface = "bold"
      )
    )

    tg <- styled_table(df)

    grid::grid.draw(
      grid::editGrob(
        tg,
        vp = grid::viewport(
          x = 0.5,
          y = 0.72,
          width = 0.95,
          height = 0.35
        )
      )
    )
  }

  add_summary_dashboard <- function(
    global_metrics,
    fit_distribution,
    screened_summary = NULL,
    poor_fit_ids = NULL
  ) {

    grid::grid.newpage()

    grid::grid.text(
      "Evaluation Summary",
      y = 0.97,
      gp = grid::gpar(
        fontsize = 18,
        fontface = "bold"
      )
    )

    draw_block <- function(title, df, subtitle, x, y) {

      if (is.null(df) || nrow(df) == 0) {
        return(NULL)
      }

      tg <- styled_table(df)

      # ----------------------------
      # Block title
      # ----------------------------
      grid::grid.text(
        title,
        x = x,
        y = y + 0.19,
        gp = grid::gpar(
          fontsize = 12,
          fontface = "bold"
        )
      )

      # ----------------------------
      # Block subtitle
      # ----------------------------
      grid::grid.text(
        subtitle,
        x = x,
        y = y + 0.155,
        gp = grid::gpar(
          fontsize = 9.5,
          col = "#4A5568",
          fontface = "bold"
        )
      )

      # ----------------------------
      # Table
      # ----------------------------
      grid::grid.draw(
        grid::editGrob(
          tg,
          vp = grid::viewport(
            x = x,
            y = y,
            width = 0.42,
            height = 0.22
          )
        )
      )
    }

    # --------------------------------
    # Top left
    # --------------------------------
    draw_block(
      "Global Performance Metrics",
      global_metrics,
      "Overall predictive performance across evaluated occasions.
       Lower absolute bias and higher IF values indicate better performance.",
      x = 0.25,
      y = 0.72
    )

    # --------------------------------
    # Top right
    # --------------------------------
    draw_block(
      "Fit Distribution",
      fit_distribution,
      "Distribution of observations by fit quality category.",
      x = 0.75,
      y = 0.72
    )

    # --------------------------------
    # Bottom left
    # --------------------------------
    draw_block(
      "Screen Fit Summary",
      screened_summary,
      "Observations matching selected screening criteria.
       Useful for rapid identification of poorly fitted samples.",
      x = 0.25,
      y = 0.24
    )

    # --------------------------------
    # Bottom right
    # --------------------------------
    draw_block(
      "Poorly Fitted IDs",
      poor_fit_ids,
      "Subjects with the highest proportion of poor predictions.
       Higher mean absolute IPE suggests potential model mismatch.",
      x = 0.75,
      y = 0.24
    )
  }


  add_plot_page <- function(title, plot_obj) {

    if (is.null(plot_obj)) {
      return(invisible(NULL))
    }

    grid::grid.newpage()

    grid::grid.text(
      title,
      y = 0.97,
      gp = grid::gpar(
        fontsize = 16,
        fontface = "bold"
      )
    )

    print(
      plot_obj,
      vp = grid::viewport(
        x = 0.5,
        y = 0.45,
        width = 0.9,
        height = 0.82
      )
    )
  }

  # --------------------------------
  # Logo
  # --------------------------------
  if (is.null(logo_path)) {
    logo_path <- system.file(
      "figures",
      "logo_xeval.png",
      package = "exeval"
    )
  }

  if (!nzchar(logo_path) || !file.exists(logo_path)) {
    include_logo <- FALSE
    logo_path <- NULL
  }

  # --------------------------------
  # Input dispatch
  # --------------------------------
  metadata <- NULL
  metrics_obj <- NULL
  metrics_obs <- NULL
  summary_obj <- NULL
  eval_obj <- NULL

  if (inherits(x, "EvalPPK")) {

    eval_obj <- x
    metrics_obj <- x$metrics
    metrics_obs <- metrics_obj$metrics

    metadata <- attr(x, "attributes")
    colnames(metadata) <- c("Parameter", "Value")

    summary_obj <- summary(
      x,
      occ = occ
    )

  } else if (inherits(x, "EvalMetricsPPK")) {

    metrics_obj <- x
    metrics_obs <- x$metrics

    metadata <- data.frame(
      Parameter = c(
        "Evaluation type",
        "Assessment",
        "Tool"
      ),
      Value = c(
        attr(x, "eval_type"),
        attr(x, "assessment"),
        attr(x, "tool")
      )
    )

  } else if (is.data.frame(x)) {

    metrics_obj <- x
    metrics_obs <- x

  } else {
    stop(
      "'x' must be an EvalPPK, EvalMetricsPPK, or data.frame."
    )
  }

  # --------------------------------
  # Fallback summary
  # --------------------------------
  if (is.null(summary_obj)) {

    df <- metrics_obs

    if (!is.null(occ) && "OCC" %in% names(df)) {
      df <- dplyr::filter(df, OCC == occ)
    }

    df_fit <- df %>%
      dplyr::mutate(
        Fit_Class = dplyr::case_when(
          Abs_IPE <= 15 ~ "Excellent",
          Abs_IPE <= 30 ~ "Acceptable",
          Abs_IPE <= 50 ~ "Poor",
          TRUE ~ "Very Poor"
        )
      )

    summary_obj <- list(
      global_metrics = df %>%
        dplyr::summarise(
          rBIAS = mean(IPE, na.rm = TRUE),
          MAIPE = mean(APE, na.rm = TRUE),
          rRMSE = sqrt(mean(RMSE, na.rm = TRUE)) * 100,
          IF20 = mean(abs(IPE) <= 20, na.rm = TRUE) * 100,
          IF30 = mean(abs(IPE) <= 30, na.rm = TRUE) * 100
        ),
      fit_distribution = df_fit %>%
        dplyr::count(Fit_Class) %>%
        dplyr::mutate(
          Percent = 100 * n / sum(n)
        ),
      poor_fit_ids = df %>%
        dplyr::filter((Abs_IPE) >= 50) %>%
        dplyr::count(ID, sort = TRUE)
    )
  }

  # --------------------------------
  # Screen fit summary
  # --------------------------------
  screened_summary <- NULL

  if (include_screen_fit) {

    screened <- screen_fit(
      x = metrics_obj,
      occ = occ,
      fit_classes = fit_classes
    )

    if (nrow(screened) > 0) {
      screened_summary <- screened %>%
        dplyr::count(Fit_Class)
    }
  }

  # --------------------------------
  # PDF
  # --------------------------------
  grDevices::pdf(
    file = file,
    width = 8.5,
    height = 11
  )

  # cover
  add_title_page(
    metadata = metadata,
    logo = if (include_logo) logo_path else NULL
  )

  # --------------------------------
  # Summary dashboard
  # --------------------------------
  add_summary_dashboard(
    global_metrics = summary_obj$global_metrics,
    fit_distribution = summary_obj$fit_distribution,
    screened_summary = screened_summary,
    poor_fit_ids = summary_obj$poor_fit_ids
  )

  # fit distribution plot
  if (include_plots) {
    add_plot_page(
      "Fit Distribution Plot",
      plot_fit_distribution(metrics_obj)
    )
  }
  # --------------------------------
  # Metrics plots
  # --------------------------------
  if (
    include_metrics_plot &&
    inherits(metrics_obj, "EvalMetricsPPK")
  ) {

    for (plot_type in metrics_plot_types) {

      p_metrics <- tryCatch(
        metrics_plot(
          metrics_obj,
          type = plot_type
        ),
        error = function(e) NULL
      )

      add_plot_page(
        paste(
          "Performance Plot:",
          pretty_eval_name(plot_type)
        ),
        p_metrics
      )
    }
  }


  # individual plots
  if (
    include_individual_plots &&
    !is.null(eval_obj) &&
    nrow(summary_obj$poor_fit_ids) > 0
  ) {

    ids_to_plot <- utils::head(
      summary_obj$poor_fit_ids$ID,
      n_individual_plots
    )

    for (id in ids_to_plot) {

      p <- tryCatch(
        plot_individual_fit(
          simulations = eval_obj$simulations,
          id = id,
          occ = occ
        ),
        error = function(e) NULL
      )

      add_plot_page(
        paste("Individual Fit ID", id),
        p
      )
    }
  }

  grDevices::dev.off()

  message(
    "PDF report exported to: ",
    normalizePath(file, mustWork = FALSE)
  )

  invisible(file)
}
